function(params: CreateAgentParams): Task {
  // 1. 创建子 Agent 的独立状态
  const agent = new Agent({
    capabilities: params.allowedTools,
    prompt: params.taskDescription,
    parentContext: this.context
  });

  // 2. 将 Agent 包装为任务返回
  return new LocalAgentTask(agent);
}

async sendMessage(to: AgentId, content: string): Promise<void> {
  const message: Message = {
    from: this.currentAgent.id,
    to,
    content,
    timestamp: Date.now()
  };

  // 放入消息队列，目标 Agent 会轮询获取
  await this.messageQueue.enqueue(message);
}

class Coordinator {
  private activeAgents = new Map<AgentId, Agent>();
  private resourceLocks = new Set<FilePath>();

  async allocate(agent: Agent, resource: FilePath): Promise<boolean> {
    if (this.resourceLocks.has(resource)) {
      return false; // 资源已被占用
    }
    this.resourceLocks.add(resource);
    return true;
  }
}

interface Team {
  id: string;
  members: Agent[];
  sharedContext: Context;

  async distribute(task: Task): Promise<Agent> {
    // 根据负载和专长选择最合适的成员
    return this.members.sort((a, b) => a.load - b.load)[0];
  }
}

async createWorktree(sourceBranch: string): Promise<string> {
  const worktreePath = `.claude/worktrees/${randomId()}`;

  // 创建隔离的工作树
  await exec(
    `git worktree add -b ${randomBranch()} ${worktreePath} ${sourceBranch}`
  );

  return worktreePath; // Agent 在此路径下工作
}
